def test_merge_asof_indicator_true():
    """Test that indicator=True creates _merge column"""
    import pandas as pd
    import pandas._testing as tm

    left = pd.DataFrame(
        {"a": [1, 5, 10], "left_val": ["a", "b", "c"]},
        index=[0, 1, 2]
    )
    right = pd.DataFrame(
        {"a": [1, 2, 3, 6, 7], "right_val": [1, 2, 3, 6, 7]},
        index=[0, 1, 2, 3, 4]
    )

    result = pd.merge_asof(left, right, on="a", indicator=True)

    # Check that _merge column exists
    assert "_merge" in result.columns

    # Check that _merge column has the right values
    assert result["_merge"].dtype.name == "category"
    assert list(result["_merge"].cat.categories) == ["left_only", "right_only", "both"]

    # All rows should be 'both' since all left values match right values
    assert (result["_merge"] == "both").all()

    print("✓ test_merge_asof_indicator_true passed")


